{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "확정_결정": [
      {
        "내용": "공개 릴리스 목표 시각은 금요일 15:00 KST로 한다.",
        "조건": "스모크 테스트 통과 시에만 적용"
      },
      {
        "내용": "packageName 불일치 발생 시, 먼저 패키지 설정(계약)을 점검한다.",
        "추가원칙": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트 검토"
      }
    ],
    "기각_제안": [
      {
        "제안자": "Hara",
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결과": "기각"
      }
    ],
    "내부_스트레치_목표": [
      {
        "내용": "수요일 릴리스 제안",
        "상태": "내부 스트레치 목표로만 유지(확정 일정 아님)"
      }
    ],
    "비결정_사항": [
      {
        "내용": "README 설치 단계는 가능하면 목요일에 검토",
        "비고": "담당자 미지정"
      }
    ],
    "리스크": [
      "tarball 경로가 잘못되면 릴리스 지연 가능",
      "README 설치 단계가 오래된 경우 릴리스 노트가 사용자 오해를 유발할 수 있음"
    ],
    "오픈_질문": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토",
      "due": "가능하면 목요일",
      "status": "담당자 미지정",
      "source_certainty": "tentative"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 확인",
      "due": "기한 미정",
      "status": "선행조건 대기",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "다음_확인사항": [
      "금요일 10:00 KST 이전/직후 Minjun 스모크 결과 확보",
      "금요일 12:00 KST Doyun 트리아지 노트 작성 완료 여부 확인",
      "스모크 통과 시 금요일 15:00 KST 공개 릴리스 진행 여부 확정",
      "Hara의 tarball 경로 점검 결과 반영",
      "최종 릴리스 승인 권한자 지정",
      "릴리스 노트에 수요일 스트레치 목표 언급 여부 결정"
    ],
    "추가_비고": [
      "수요일 일정은 내부 스트레치 목표이며 외부 확정 일정으로 취급하지 않음",
      "packageName mismatch는 무시하지 않고 계약(패키지 설정) 우선 점검 원칙 유지"
    ]
  },
  "non_invention_rules": [
    "고객명/외부 파트너 정보를 추가하지 않는다.",
    "예산 수치나 비용 결정을 추가하지 않는다.",
    "보안 사고, 운영 장애(프로덕션 아웃티지) 사실을 추가하지 않는다.",
    "법무 승인 필요 사실을 추가하지 않는다.",
    "미지정 담당자(예: README 검토 담당)를 임의 지정하지 않는다.",
    "명시되지 않은 마감일(예: Hara 작업 기한)을 임의 설정하지 않는다.",
    "결정되지 않은 사항(최종 승인권자, 릴리스 노트 문구)을 확정된 사실로 쓰지 않는다."
  ]
}
